//! Automatic tests for the BAML compiler.
//!
//! Tests are auto-generated from the projects/ directory by build.rs.
//! To add a test, simply create a new folder in projects/ with BAML files.

#![cfg(test)]

pub mod utils;

// Include the tests generated by build.rs
include!(concat!(env!("OUT_DIR"), "/generated_tests.rs"));

// Helper function for formatting syntax trees
fn format_syntax_tree(node: &baml_db::baml_syntax::SyntaxNode) -> String {
    format_node_recursive(node, 0)
}

fn format_node_recursive(node: &baml_db::baml_syntax::SyntaxNode, depth: usize) -> String {
    use baml_db::baml_syntax::NodeOrToken;

    let mut result = String::new();
    let indent = "  ".repeat(depth);

    result.push_str(&format!("{}{:?}", indent, node.kind()));

    // For leaf nodes (tokens), include the text
    if node.first_child().is_none() {
        let text = node.text().to_string();
        if !text.trim().is_empty() {
            result.push_str(&format!(" \"{}\"", text));
        }
    }

    result.push('\n');

    // Iterate over both nodes and tokens
    for child in node.children_with_tokens() {
        match child {
            NodeOrToken::Node(child_node) => {
                result.push_str(&format_node_recursive(&child_node, depth + 1));
            }
            NodeOrToken::Token(token) => {
                // Show tokens (but skip trivia for readability)
                if !token.kind().is_trivia() {
                    result.push_str(&format!(
                        "{}{:?} \"{}\"\n",
                        "  ".repeat(depth + 1),
                        token.kind(),
                        token.text()
                    ));
                }
            }
        }
    }

    result
}
